SELECT * FROM appointments



            AND coach_id = #{request.params.coachId}


            AND student_id = #{request.params.studentId}


            AND table_id = #{request.params.tableId}


            AND status = #{request.params.status}


            AND DATE(start_time) >= #{request.params.startDate}


            AND DATE(start_time) <= #{request.params.endDate}



ORDER BY start_time DESC

SELECT * FROM appointments 
WHERE coach_id = #{coachId}
AND start_time >= #{startTime}
AND start_time <= #{endTime}
AND status IN (0, 1)
ORDER BY start_time ASC

SELECT a.* FROM appointments a LEFT JOIN evaluations e ON a.id = e.appointment_id WHERE a.status = 2 AND e.id IS NULL
AND a.student_id = #{userId}
AND a.coach_id = #{userId}
ORDER BY a.end_time DESC

SELECT COUNT(*) FROM appointments 
WHERE status = 3
AND DATE_FORMAT(create_time, '%Y-%m') = DATE_FORMAT(NOW(), '%Y-%m')

    AND student_id = #{userId}


    AND coach_id = #{userId}

SELECT a.id, a.coach_id, a.student_id, a.table_id, a.start_time, a.end_time, a.cost, a.status, a.create_time, COALESCE(coach.real_name, coach.username) AS coach_name, COALESCE(student.real_name, student.username) AS student_name, t.table_number, c.name AS campus_name, coach.coach_level FROM appointments a LEFT JOIN users coach ON a.coach_id = coach.id LEFT JOIN users student ON a.student_id = student.id LEFT JOIN tables t ON a.table_id = t.id LEFT JOIN campus c ON t.campus_id = c.id
AND a.coach_id = #{request.params.coachId}
AND a.student_id = #{request.params.studentId}
AND a.table_id = #{request.params.tableId}
AND a.status = #{request.params.status}
AND DATE(a.start_time) >= #{request.params.startDate}
AND DATE(a.start_time) <= #{request.params.endDate}
AND DATE(a.start_time) = #{request.params.startTime}
AND t.campus_id = #{request.params.campusId}
ORDER BY a.start_time DESC
